#include<bits/stdc++.h>
#define MAXN 200010
#define INF 0x7fffffff
#define LL long long
using namespace std;

// Dinic
struct node
{
	int v, rev, cap;
};

int n, m;
vector <node> g[MAXN];
int level[MAXN], iter[MAXN];

void addEdge(int u, int v, int cap)
{
	g[u].push_back((node){v, (int)g[v].size(), cap});
	g[v].push_back((node){u, (int)g[u].size()-1, 0}); // 反向边
}

void buildLevel(int st)
{
	for(int x = 0; x < n; x++) level[x] = -1;
	queue <int> q;
	level[st] = 0;
	q.push(st);
	while(!q.empty())
	{
		int u = q.front(); q.pop();
		for(int x = 0; x < g[u].size(); x++)
		{
			int v = g[u][x].v, cap = g[u][x].cap;
			if(cap > 0 && level[v] < 0)
			{
				level[v] = level[u] + 1;
				q.push(v);
			}
		}
	}
}

int DinicDFS(int u, int ed, int upToFlow)
{
	if(u == ed) return upToFlow;int out=0;
	for(int &x = iter[u]; x < g[u].size(); x++)
	{
		int v = g[u][x].v, rev = g[u][x].rev, cap = g[u][x].cap;
		if(cap > 0 && level[u] < level[v])
		{
			int d = DinicDFS(v, ed, min(upToFlow, cap));
			g[u][x].cap -= d;
			g[v][rev].cap += d;
			out+=d;
			if(!(upToFlow-=d))break;
		}
	}
	if(!out)level[u]=-1;
	return out;
}

int Dinic(int st, int ed)
{
	int maxFlow = 0;
	while(1)
	{
		buildLevel(st);
		if(level[ed] < 0) break; // 到不了终点
		for(int x = 0; x < n; x++) iter[x] = 0; // 注意下标
		int f;
		while((f = DinicDFS(st, ed, INF)) > 0) maxFlow += f;
	}
	return maxFlow;
}

// Bigraph Match
int n1, n2, S, T;

struct edge
{
	int u, v;
};

bool ing[MAXN];

vector <edge> biMatchEdge() // 基于残量网络找匹配边
{
	vector <edge> re;
	for(int u = 0; u < n1; u++)
	{
		for(int x = 0; x < g[u].size(); x++)
		{
			int v = g[u][x].v, cap = g[u][x].cap;
			if(v >= n1 && v < n1 + n2 && cap == 0) re.push_back((edge){u, v-n1});
		}
	}
	return re;
}

// FUCK
struct cor {
    int x, y, id;
} cas[MAXN], waint[MAXN];

bool cmp1(cor a, cor b) {
    if(a.x == b.x) return a.y < b.y;
    return a.x < b.x;
}

bool cmp2(cor a, cor b) {
    if(a.y == b.y) return a.x < b.x;
    return a.y < b.y;
}

int rowv[MAXN], colv[MAXN];
bool isAns[MAXN], rowatk[MAXN], colatk[MAXN];
bool n1b[MAXN], n2b[MAXN];
int n1mp[MAXN], n2mp[MAXN], fn1mp[MAXN], fn2mp[MAXN];

void Solve() {
    // memset(cas, 0, sizeof(cas));
    // memset(waint, 0, sizeof(waint));

    int ans = 0;
    int N, M, K;
    cin >> N >> M >> K;
    for(int i = 1; i <= N; i++) {
        cin >> cas[i].x >> cas[i].y;
        cas[i].id = i;
        rowatk[i] = colatk[i] = false;
    }
    for(int i = 0; i <= N; i++) {
        n1b[i] = n2b[i] = n1mp[i] = n2mp[i] = fn1mp[i] = fn2mp[i] = 0;
    }
    for(int i = 1; i <= M; i++) {
        cin >> waint[i].x >> waint[i].y;
        waint[i].id = i;
        rowv[i] = colv[i] = 0;
        isAns[i] = true;
    }

    sort(cas+1, cas+N+1, cmp1);
    sort(waint+1, waint+M+1, cmp1);
    int wj = 1;
    for(int i = 1; i < N; i++) {
        if(cas[i].x == cas[i+1].x) {
            ans++;
            rowatk[cas[i].id] = true;
            if(wj > M) continue;
            while((waint[wj].x < cas[i].x) || (waint[wj].x == cas[i].x && waint[wj].y < cas[i+1].y)) {
                if(waint[wj].x == cas[i].x && waint[wj].y > cas[i].y) {
                    rowv[waint[wj].id] = cas[i].id;
                }
                wj++;
                if(wj > M) break;
            }
        }
    }

    sort(cas+1, cas+N+1, cmp2);
    sort(waint+1, waint+M+1, cmp2);
    wj = 1;
    for(int i = 1; i < N; i++) {
        if(cas[i].y == cas[i+1].y) {
            ans++;
            colatk[cas[i].id] = true;
            if(wj > M) continue;
            while((waint[wj].y < cas[i].y) || (waint[wj].y == cas[i].y && waint[wj].x < cas[i+1].x)) {
                if(waint[wj].y == cas[i].y && waint[wj].x > cas[i].x) {
                    colv[waint[wj].id] = cas[i].id;
                }
                wj++;
                if(wj > M) break;
            }
        }
    }

    // for(int i = 1; i <= M; i++) {
    //     cout << "WJ: " << i << endl;
    //     cout << rowv[i] << endl;
    //     // cout << "----" << endl;
    //     cout << colv[i] << endl;
    // }
    int n1cnt = 0, n2cnt = 0;
    unordered_map <LL, int> mp;
    vector <int> pairv, sigv, sbv;
    vector <pair<int, int>> edges;
    for(int i = 1; i <= M; i++) {
        if(rowv[i] && colv[i]) {
            pair <int, int> pp = {rowv[i], colv[i]};
            int u = pp.first-1, v = pp.second-1;
            // cout << u << " " << v << endl;
            if(!n1b[u]) {
                n1mp[u] = n1cnt;
                fn1mp[n1cnt] = u;
                n1b[u] = true;
                n1cnt++;
            }
            if(!n2b[v]) {
                n2mp[v] = n2cnt;
                fn2mp[n2cnt] = v;
                n2b[v] = true;
                n2cnt++;
            }
            LL tmp = 1ll * pp.first * (N+5) + pp.second;
            mp[tmp] = i;
            pairv.push_back(i);
            edges.push_back(pp);
        } else if(rowv[i] || colv[i]) {
            sigv.push_back(i);
        } else {
            sbv.push_back(i);
        }
    }

    // cout << n1cnt << " " << n2cnt << endl;
    n1 = n1cnt;
    n2 = n2cnt;
    n = n1 + n2 + 2;
    S = n1 + n2;
    T = S + 1;
    for(int i = 0; i < n; i++) {
        g[i].clear();
        level[i] = iter[i] = 0;
    }
    for(auto a : edges) {
        // cout << "---" << endl;
        // cout << a.first-1 << " " << a.second-1 << endl;
        // cout << n1mp[a.first-1] << " " << n2mp[a.second-1] << endl;
        addEdge(n1mp[a.first-1], n2mp[a.second-1] + n1, 1);
    }
    for(int x = 0; x < n1; x++) addEdge(S, x, 1);
    for(int x = 0; x < n2; x++) addEdge(x+n1, T, 1);
    // cout << ans << endl;
    // cout << pairv.size() << endl;
    // cout << sigv.size() << endl;
    // cout << sbv.size() << endl;
    // for(int x = 0; x < N; x++) {
    //     addEdge(S, x, 1);
    //     addEdge(x+N, T, 1);
    // }
    Dinic(S, T);
    vector <edge> edgeAns = biMatchEdge();
    // cout << edgeAns.size() << endl;
    for(auto &a : edgeAns) {
        // cout << "!!!: " << endl;
        // cout << a.u << " " << a.v << endl;
        // cout << fn1mp[a.u] << " " << fn2mp[a.v] << endl;
        a.u = fn1mp[a.u];
        a.v = fn2mp[a.v];
    }

    K = M-K; // 保留 K 个障碍物

    for(auto a : edgeAns) {
        if(K <= 0) break;
        pair <int, int> pp = {a.u+1, a.v+1};
        LL tmp = 1ll * pp.first * (N+5) + pp.second;
        isAns[mp[tmp]] = false;
        rowatk[pp.first] = false;
        colatk[pp.second] = false;
        K--;
        ans -= 2;
    }
    for(int a : pairv) {
        if(K <= 0) break;
        // cout << rowatk[rowv[a]] << endl;
        // cout << colatk[colv[a]] << endl;
        if(rowatk[rowv[a]] || colatk[colv[a]]) {
            isAns[a] = false;
            ans--;
            K--;
            rowatk[rowv[a]] = colatk[colv[a]] = false;
        }
    }
    for(int a : sigv) {
        if(K <= 0) break;
        if(rowatk[rowv[a]] || colatk[colv[a]]) {
            isAns[a] = false;
            ans--;
            K--;
            rowatk[rowv[a]] = colatk[colv[a]] = false;
        }
    }
    for(int a : sbv) {
        if(K <= 0) break;
        isAns[a] = false;
        K--;
    }
    for(int a : pairv) {
        if(K <= 0) break;
        if(isAns[a]) {
            isAns[a] = false;
            K--;
        }
    }
    for(int a : sigv) {
        if(K <= 0) break;
        if(isAns[a]) {
            isAns[a] = false;
            K--;
        }
    }
    cout << ans << endl;
    // cout << K << endl;
    for(int i = 1; i <= M; i++) {
        if(isAns[i]) cout << i << " ";
    }
    cout << endl;
}

int main() {
    cin.tie(nullptr);
    ios::sync_with_stdio(false);

    int TTT;
    cin >> TTT;
    while(TTT--) Solve();
    return 0;
}
